std::map<int, int> factorize(int x) {
    std::map<int, int> res;
    for (int i = 2; i * i <= x; i++) {
        if (x % i != 0) { continue; }
        int cnt = 0;
        while (x % i == 0) 
            ++cnt, x /= i;

        res[i] = cnt;
    }
    if (x > 1) { ++res[x]; }
    return res;
}

void solve() {
	int n;
