    for(int i = 1; i <= n; i++){
        if(i == 1)g[1] = gcd(a[1], a[2]);
        else if(i == n)g[n] = gcd(a[n], a[n - 1]);
        else g[i] = lcm(gcd(a[i], a[i - 1]), gcd(a[i], a[i + 1]));
        if(g[i] > b[i])g[i] = a[i];
